SELECT model_id, AVG(nobs) AS average_observations
FROM model_metrics
GROUP BY model_id;

SELECT report_data, MAX(generation_date) AS latest_generation_date
FROM model_reports
GROUP BY report_data;

SELECT AIC
FROM model_metrics
WHERE metric_id = 0;

SELECT COUNT(*) AS report_count
FROM model_reports
WHERE generation_date = '2023-05-05';
